(function(w){"use strict";const ID="median";function compute(x){const raw=String(x.values||"").split(/[\s,]+/).filter(Boolean);const values=raw.map(Number);if(!values.length||values.some(v=>!Number.isFinite(v)))return{error:"숫자를 쉼표 또는 공백으로 구분해 입력해 주세요."};values.sort((a,b)=>a-b);const n=values.length;const median=n%2?values[(n-1)/2]:(values[n/2-1]+values[n/2])/2;return{count:n,median,min:values[0],max:values[n-1]}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-median-values">숫자 입력</label><textarea id="hm-median-values" class="hm-calc-textarea" rows="4" placeholder="예: 3, 7, 9, 11, 15"></textarea><p class="hm-calc-hint">쉼표 또는 공백으로 구분하세요.</p></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">중앙값 계산하기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const v=root.querySelector("textarea"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({values:v.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("중앙값",api.formatNumber(r.median,8),`<dl><dt>개수</dt><dd>${r.count}개</dd><dt>최솟값</dt><dd>${api.formatNumber(r.min,8)}</dd><dt>최댓값</dt><dd>${api.formatNumber(r.max,8)}</dd></dl>`));});reset.addEventListener("click",()=>{v.value="";api.setMessage(msg,"");api.clearResult(res);v.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
